import React from "react";

import type { SteezIconProps } from "@steez-ui/icons";

import styles from "./RuntimeOrbitDiagram.module.css";

export interface RuntimeOrbitNode {
  id: string;
  label: string;
  icon: React.ComponentType<SteezIconProps>;
  x: number;
  y: number;
}

export interface RuntimeOrbitDiagramProps {
  nodes: RuntimeOrbitNode[];
  className?: string;
  durationSeconds?: number;
  pathOrder?: readonly string[];
  iconSize?: number;
}

function buildPath(points: RuntimeOrbitNode[]) {
  if (points.length === 0) {
    return "";
  }

  return `${points
    .map((point, index) =>
      `${index === 0 ? "M" : "L"} ${point.x.toFixed(2)} ${point.y.toFixed(2)}`,
    )
    .join(" ")} Z`;
}

export function RuntimeOrbitDiagram({
  nodes,
  className = "",
  durationSeconds = 5.4,
  pathOrder,
  iconSize = 22,
}: RuntimeOrbitDiagramProps) {
  const orderedNodes = React.useMemo(() => {
    if (!pathOrder?.length) {
      return nodes;
    }

    const nodeMap = new Map(nodes.map((node) => [node.id, node] as const));
    const sequence = pathOrder
      .map((id) => nodeMap.get(id))
      .filter((node): node is RuntimeOrbitNode => Boolean(node));

    return sequence.length === nodes.length ? sequence : nodes;
  }, [nodes, pathOrder]);

  const pathD = React.useMemo(() => buildPath(orderedNodes), [orderedNodes]);
  const nodeSequenceIndex = React.useMemo(
    () => new Map(orderedNodes.map((node, index) => [node.id, index] as const)),
    [orderedNodes],
  );

  return (
    <div
      className={`${styles.root} ${className}`.trim()}
      style={{ "--orbit-duration": `${durationSeconds}s` } as React.CSSProperties}
    >
      <svg
        className={styles.svg}
        viewBox="0 0 100 100"
        preserveAspectRatio="none"
        aria-hidden="true"
      >
        {pathD ? <path className={styles.track} d={pathD} pathLength={100} /> : null}
        {pathD ? <path className={styles.pathLine} d={pathD} pathLength={100} /> : null}
        {pathD ? (
          <circle className={styles.dot} cx="0" cy="0" r="1.45">
            <animateMotion
              calcMode="linear"
              dur={`${durationSeconds}s`}
              path={pathD}
              repeatCount="indefinite"
            />
          </circle>
        ) : null}
      </svg>

      {nodes.map((node) => {
        const IconComponent = node.icon;
        const sequenceIndex = nodeSequenceIndex.get(node.id) ?? 0;
        const nodeDelayMs = Math.round(
          (durationSeconds * 1000 * sequenceIndex) /
            Math.max(orderedNodes.length, 1) -
            120,
        );

        return (
          <div
            key={node.id}
            className={styles.node}
            style={
              {
                "--node-x": `${node.x}%`,
                "--node-y": `${node.y}%`,
                "--node-delay": `${nodeDelayMs}ms`,
              } as React.CSSProperties
            }
            title={node.label}
          >
            <div className={styles.nodeInner}>
              <IconComponent width={iconSize} height={iconSize} />
            </div>
            <span className={styles.srOnly}>{node.label}</span>
          </div>
        );
      })}
    </div>
  );
}

export default RuntimeOrbitDiagram;

.root {
  --orbit-duration: 5.4s;

  position: relative;
  width: min(100%, 38rem);
  aspect-ratio: 1;
  min-height: 22rem;
  isolation: isolate;
}

.svg {
  width: 100%;
  height: 100%;
  display: block;
  overflow: visible;
}

.track {
  fill: none;
  stroke: color-mix(in srgb, var(--text-primary) 14%, transparent);
  stroke-width: 0.8;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.pathLine {
  fill: none;
  stroke: color-mix(in srgb, var(--accent-primary) 88%, transparent);
  stroke-width: 1.35;
  stroke-linecap: round;
  stroke-linejoin: round;
  stroke-dasharray: 14 86;
  animation: orbitPath var(--orbit-duration) linear infinite;
}

.node {
  position: absolute;
  top: var(--node-y);
  left: var(--node-x);
  width: clamp(4.15rem, 8vw, 4.95rem);
  aspect-ratio: 1;
  translate: -50% -50%;
  display: grid;
  place-items: center;
  border-radius: 999px;
  color: color-mix(in srgb, var(--text-secondary) 92%, transparent);
  border: 1px solid color-mix(in srgb, var(--border-color) 78%, transparent);
  background: color-mix(in srgb, var(--bg-secondary) 94%, transparent);
  box-shadow: 0 0 0 1px color-mix(in srgb, var(--bg-primary) 28%, transparent);
  animation: orbitPulse var(--orbit-duration) linear infinite;
  animation-delay: var(--node-delay);
  transition:
    border-color var(--tile-hover-duration, 220ms) ease,
    transform var(--tile-hover-duration, 220ms) ease,
    background-color var(--tile-hover-duration, 220ms) ease;
}

.node:hover {
  color: var(--text-primary);
  border-color: color-mix(in srgb, var(--accent-primary) 46%, var(--border-color));
  transform: translateY(-1px);
}

.nodeInner {
  width: calc(100% - 10px);
  height: calc(100% - 10px);
  display: grid;
  place-items: center;
  border-radius: inherit;
  background: color-mix(in srgb, var(--bg-primary) 96%, transparent);
}

.nodeInner svg {
  width: 48%;
  height: 48%;
  color: currentColor;
  opacity: 0.88;
  transform: scale(0.86);
  transition:
    opacity var(--tile-hover-duration, 220ms) ease,
    transform var(--tile-hover-duration, 220ms) ease,
    color var(--tile-hover-duration, 220ms) ease;
}

.node:hover .nodeInner svg {
  opacity: 1;
  transform: scale(0.92);
}

.dot {
  fill: var(--accent-primary);
  filter: drop-shadow(
    0 0 8px color-mix(in srgb, var(--accent-primary) 32%, transparent)
  );
}

.srOnly {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

@keyframes orbitPath {
  from {
    stroke-dashoffset: 0;
  }

  to {
    stroke-dashoffset: -100;
  }
}

@keyframes orbitPulse {
  0%,
  4%,
  16%,
  100% {
    color: color-mix(in srgb, var(--text-secondary) 92%, transparent);
    border-color: color-mix(in srgb, var(--border-color) 78%, transparent);
    background: color-mix(in srgb, var(--bg-secondary) 94%, transparent);
    box-shadow: 0 0 0 1px color-mix(in srgb, var(--bg-primary) 28%, transparent);
  }

  6%,
  13% {
    color: var(--text-primary);
    border-color: color-mix(in srgb, var(--accent-primary) 64%, var(--border-color));
    background: color-mix(in srgb, var(--accent-primary) 12%, var(--bg-secondary));
    box-shadow:
      0 0 0 1px color-mix(in srgb, var(--accent-primary) 24%, transparent),
      0 0 22px color-mix(in srgb, var(--accent-primary) 18%, transparent);
  }
}

@media (max-width: 720px) {
  .root {
    min-height: 18rem;
  }

  .node {
    width: clamp(3.55rem, 17vw, 4.25rem);
  }
}

@media (prefers-reduced-motion: reduce) {
  .pathLine,
  .node {
    animation: none;
  }

  .dot {
    display: none;
  }
}
